{
  "$schema": "https://metaharness.dev/schemas/mcp-policy/v1",
  "description": "Default-deny MCP policy for @metaharness/example-qiskit. All mutations (circuit write, job submit, transpile-with-write) are gated behind --allow-mutations. Read/inspect/simulate paths are granted for sandbox use.",
  "defaultDeny": true,
  "allowShell": false,
  "allowNetwork": false,
  "allowFileWrite": false,
  "requireApprovalForDangerous": true,
  "toolTimeoutMs": 45000,
  "maxToolCallsPerTurn": 12,
  "auditLog": true,
  "auditLogPath": ".harness/audit/mcp-calls.jsonl",
  "mutations_require_flag": "--allow-mutations",
  "grantedTools": [
    {
      "tool": "Read",
      "reason": "Agents read existing circuit files, transpile results, and job metadata."
    },
    {
      "tool": "WebSearch",
      "reason": "Planner searches Qiskit documentation and IBM Quantum device calibration data."
    },
    {
      "tool": "WebFetch",
      "reason": "Planner and verifier fetch IBM Quantum REST API responses (read-only GET calls)."
    },
    {
      "tool": "mcp__qiskit-sandbox__circuit_inspect",
      "reason": "Read circuit gate list, depth, and qubit count without executing."
    },
    {
      "tool": "mcp__qiskit-sandbox__backend_list",
      "reason": "List available backends and their queue depths (read-only)."
    },
    {
      "tool": "mcp__qiskit-sandbox__backend_properties",
      "reason": "Fetch T1/T2, gate error, and readout error for a named backend (read-only)."
    },
    {
      "tool": "mcp__qiskit-sandbox__simulate_statevector",
      "reason": "Run local statevector simulation via qiskit-aer — no real hardware, no job submission."
    },
    {
      "tool": "mcp__qiskit-sandbox__transpile_dry_run",
      "reason": "Transpile a circuit to a target basis gate set and return the result in memory — does not write files."
    },
    {
      "tool": "mcp__qiskit-sandbox__job_status",
      "reason": "Fetch the status of a previously submitted job by job ID (read-only)."
    },
    {
      "tool": "mcp__qiskit-sandbox__job_result_fetch",
      "reason": "Retrieve counts or statevector for a completed job (read-only)."
    }
  ],
  "deniedTools": [
    {
      "tool": "mcp__qiskit-sandbox__job_submit",
      "reason": "Submits a real hardware job and incurs IBM Quantum usage credit. Gated behind --allow-mutations."
    },
    {
      "tool": "mcp__qiskit-sandbox__circuit_write",
      "reason": "Writes a .qpy or .qasm file to disk. Gated behind --allow-mutations."
    },
    {
      "tool": "mcp__qiskit-sandbox__transpile_write",
      "reason": "Transpiles and writes the output circuit to a file. Gated behind --allow-mutations."
    },
    {
      "tool": "Bash",
      "reason": "Arbitrary shell access is never granted — use the qiskit-sandbox MCP tools instead."
    },
    {
      "tool": "Write",
      "reason": "File writes require --allow-mutations."
    }
  ],
  "sandboxDefaults": {
    "backendOverride": "aer_simulator",
    "shots": 1024,
    "simulationOnly": true
  }
}
